-- Ken's Hardened V2 Fix

local b64_0xIIIlII = {}
local char_0x1IIIlI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIlI1II=1,#char_0x1IIIlI do b64_0xIIIlII[char_0x1IIIlI:sub(i_0xIlI1II,i_0xIlI1II)] = i_0xIlI1II - 1 end

function b64_0xIIIlII.dec_0x1I1lII(d_0xIll1lI)
    d_0xIll1lI = string.gsub(d_0xIll1lI, '[^'..char_0x1IIIlI..'=]', '')
    local r_0x1I1l1I = {}
    for i_0xIlI1II=1, #d_0xIll1lI, 4 do
        local c_0xl1Il11 = b64_0xIIIlII[d_0xIll1lI:sub(i_0xIlI1II,i_0xIlI1II)] or 0
        local c_0xIllllI = b64_0xIIIlII[d_0xIll1lI:sub(i_0xIlI1II+1,i_0xIlI1II+1)] or 0
        local c_0x11Il1l, c_0xIlII1I = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIll1lI:sub(i_0xIlI1II+2,i_0xIlI1II+2)
        if ch3 == "=" then has3 = false else c_0x11Il1l = b64_0xIIIlII[ch3] or 0 end
        local ch4 = d_0xIll1lI:sub(i_0xIlI1II+3,i_0xIlI1II+3)
        if ch4 == "=" then has4 = false else c_0xIlII1I = b64_0xIIIlII[ch4] or 0 end
        local b_0xI1IlII = c_0xl1Il11 * (2^18) + c_0xIllllI * (2^12) + c_0x11Il1l * (2^6) + c_0xIlII1I
        local b_0x11Illl = math.floor(b_0xI1IlII / (2^16)) % (2^8)
        local b_0xlIlllI = math.floor(b_0xI1IlII / (2^8)) % (2^8)
        local b_0xlI1I1l = b_0xI1IlII % (2^8)
        table.insert(r_0x1I1l1I, string.char(b_0x11Illl))
        if has3 then table.insert(r_0x1I1l1I, string.char(b_0xlIlllI)) end
        if has4 then table.insert(r_0x1I1l1I, string.char(b_0xlI1I1l)) end
    end
    return table.concat(r_0x1I1l1I)
end


local function bxor_0xI1lIIl(a_0xIl1lI1,b_0xlIIllI)
    if bit32 then return bit32.bxor(a_0xIl1lI1,b_0xlIIllI) end
    local r_0x1lIIl1 = 0
    for i_0xlIIlIl = 0, 7 do
        local x_0xlIll1I = a_0xIl1lI1 % 2
        local y_0xlI111l = b_0xlIIllI % 2
        if x_0xlIll1I ~= y_0xlI111l then r_0x1lIIl1 = r_0x1lIIl1 + (2^i_0xlIIlIl) end
        a_0xIl1lI1 = math.floor(a_0xIl1lI1 / 2)
        b_0xlIIllI = math.floor(b_0xlIIllI / 2)
    end
    return r_0x1lIIl1
end


local function bxor_str_0x1lIlI1(s_0xllIIII, k_0xI11IlI)
    local r_0xIlII1I = {}
    for i_0xIlllll=1, #s_0xllIIII do
        local b_0xlllII1 = string.byte(s_0xllIIII, i_0xIlllll)
        local kb_0xllI11I = string.byte(k_0xI11IlI, (i_0xIlllll-1) % #k_0xI11IlI + 1)
        r_0xIlII1I[i_0xIlllll] = string.char(bxor_0xI1lIIl(b_0xlllII1, kb_0xllI11I))
    end
    return table.concat(r_0xIlII1I)
end


local function getkeys_0xIl11l1()
    local seed = b64_0xIIIlII.dec_0x1I1lII("VzdrZUtxYWY=")
    local k1_enc = b64_0xIIIlII.dec_0x1I1lII("MU0fDxMEVRQ=")
    local k2_enc = b64_0xIIIlII.dec_0x1I1lII("GkUCEjIWGzQ=")
    return bxor_str_0x1lIlI1(k1_enc, seed), bxor_str_0x1lIlI1(k2_enc, seed)
end


local function cff_0x1Ill1l(a_0xIII1l1)
    local st_0xllI11l = 0
    local res_0xl1IlIl = a_0xIII1l1
    while true do
        if st_0xllI11l == 0 then
            res_0xl1IlIl = res_0xl1IlIl + 1
            st_0xllI11l = 1
        elseif st_0xllI11l == 1 then
            res_0xl1IlIl = res_0xl1IlIl * 2
            st_0xllI11l = 2
        elseif st_0xllI11l == 2 then
            res_0xl1IlIl = res_0xl1IlIl - 3
            st_0xllI11l = 3
        else
            break
        end
    end
    return res_0xl1IlIl
end


local function chain_0x1l11Il(x) return x*2 end
local function chain_0xIIlIIl(x) return chain_0x1l11Il(x)+1 end


local d_0xIIlIlI = {
  {op=255, val="", is_enc=true},
}
local pc_0xllI1Il = 1
local stk_0x1lllIl = {}
stk_0x1lllIl._jmp = nil


local disp_0xlll1II = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIl11l1()

local state_0xIIIl1I = 0
while true do
    if state_0xIIIl1I == 0 then  -- FETCH
        if pc_0xllI1Il > #d_0xIIlIlI then break end
        local inst = d_0xIIlIlI[pc_0xllI1Il]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIIIlII.dec_0x1I1lII(val)
            d = bxor_str_0x1lIlI1(d, k2)
            val = bxor_str_0x1lIlI1(d, k1)
        end
        stk_0x1lllIl._jmp = nil
        pc_0xllI1Il = pc_0xllI1Il + 1
        cur_op_0xII1I11 = opcode
        cur_val_0xI1IIl1 = val
        state_0xIIIl1I = 1

    elseif state_0xIIIl1I == 1 then  -- EXECUTE
        local handler = disp_0xlll1II[cur_op_0xII1I11]
        if handler then
            handler(stk_0x1lllIl, cur_val_0xI1IIl1)
        end
        if stk_0x1lllIl._jmp then
            pc_0xllI1Il = pc_0xllI1Il + stk_0x1lllIl._jmp
        end
        state_0xIIIl1I = 0
